import{debugLogObject}from"./debug.js";import{ConfigurationError}from"./errors.js";import{_load}from"./loader.js";const unwrapFunction=async(r,o)=>{if("function"==typeof r)try{return await r(o)}catch(r){throw debugLogObject("*","Error executing function:",r),r}return r};export async function loadResolvedConfigFile(r,o){const n=await _load(r);try{return await unwrapFunction(n,o)}catch(o){throw new ConfigurationError(`Error running the function from ${r}`)}}